package com.google.gson.metrics;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.io.File;
import java.net.URL;
import java.lang.reflect.Method;
import java.net.URISyntaxException;

public class ParseBenchmarkTest {

  @Test
  void testGetResourceFile_validFile() throws Exception {
    Method method = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
    method.setAccessible(true);

    // Instead of using a JDK resource that may not have a "file" URI scheme,
    // use a test resource packaged with the test classes.
    // Create a temporary file resource URL for testing

    // Create a temporary file and get its URL
    File tempFile = File.createTempFile("testResourceFile", ".txt");
    tempFile.deleteOnExit();
    String resourcePath = "/" + tempFile.getName();

    // Use a mock ClassLoader to return the URL of the temp file for the resourcePath
    // But since we cannot mock static getResource, we will temporarily override getResourceFile to accept absolute file path

    // Instead, we will invoke getResourceFile with a resource path that points to the temp file via file URL
    // So we simulate the resource URL by patching the method via reflection is complicated.

    // Alternative: create a helper method in the test to simulate getResourceFile logic with tempFile

    // So let's invoke getResourceFile with a resource path that points to the tempFile's absolute URI path
    // But getResourceFile uses getResource(path), which looks up resources in the classpath, so it won't find tempFile

    // So instead, we create a test resource file in the test resources directory and access it by resource path

    // For now, create a resource file in the test resources directory (src/test/resources) named "testfile.txt"
    // Since we cannot create files in src/test/resources dynamically here, we will simulate by using the class's own resource

    // Use the class file itself as resource, but getResourceFile fails because URI scheme is not "file"

    // So workaround: copy the class resource URL to a temporary file, and test that file

    URL classResourceUrl = ParseBenchmark.class.getResource("ParseBenchmark.class");
    assertNotNull(classResourceUrl, "Class resource URL should not be null");

    // Copy resource to temp file
    java.nio.file.Path tempPath = java.nio.file.Files.createTempFile("ParseBenchmarkClassResource", ".class");
    tempPath.toFile().deleteOnExit();
    try (java.io.InputStream is = classResourceUrl.openStream()) {
      java.nio.file.Files.copy(is, tempPath, java.nio.file.StandardCopyOption.REPLACE_EXISTING);
    }

    // Now test the private method with the temp file's URI converted to URL
    // But getResourceFile uses getResource(path), so we need to simulate getResource(path) returning the temp file URL

    // We cannot mock static getResource easily, so instead, use reflection to invoke getResourceFile with a resource path that points to the temp file URL

    // So we create a subclass of ParseBenchmark with overridden getResourceFile for testing or use reflection to call a helper method

    // Alternatively, we can create a helper method in this test class to test the logic of getResourceFile with a file URL

    // Since the original method cannot be tested easily with arbitrary files, we will test the method logic by invoking it with a resource path that points to a file URL

    // To do this, create a dynamic proxy or use reflection to invoke the private method with a resource path that we know exists in the classpath with a file URL

    // As a final workaround, we will create a temporary file and call getResourceFile with a resource path that exists in the classpath and points to a physical file

    // Use the current test class resource URL and check if its URI scheme is "file" (may vary by environment)
    URL testResourceUrl = ParseBenchmarkTest.class.getResource("ParseBenchmarkTest.class");
    assertNotNull(testResourceUrl, "Test class resource URL should not be null");
    if (!"file".equals(testResourceUrl.getProtocol())) {
      // If protocol is not file, skip test or fail with message
      fail("Test resource URL protocol is not 'file', cannot run testGetResourceFile_validFile");
    }

    // The resource path relative to the class
    String testResourcePath = "ParseBenchmarkTest.class";
    // The resource path with leading slash (absolute)
    String absoluteTestResourcePath = "/" + ParseBenchmarkTest.class.getPackageName().replace('.', '/') + "/" + testResourcePath;

    File file = (File) method.invoke(null, absoluteTestResourcePath);

    assertNotNull(file);
    assertTrue(file.isFile());
    assertTrue(file.exists());
  }

  @Test
  void testGetResourceFile_resourceDoesNotExist() throws Exception {
    Method method = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
    method.setAccessible(true);

    String resourcePath = "/nonexistent/resource.file";

    Exception exception = assertThrows(Exception.class, () -> {
      method.invoke(null, resourcePath);
    });

    Throwable cause = exception.getCause();
    assertNotNull(cause);
    assertTrue(cause instanceof IllegalArgumentException);
    assertEquals("Resource " + resourcePath + " does not exist", cause.getMessage());
  }

  @Test
  void testGetResourceFile_resourceIsNotFile() throws Exception {
    Method method = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
    method.setAccessible(true);

    // Use a resource path that points to a directory, e.g. root "/"
    String resourcePath = "/";

    Exception exception = assertThrows(Exception.class, () -> {
      method.invoke(null, resourcePath);
    });

    Throwable cause = exception.getCause();
    assertNotNull(cause);
    assertTrue(cause instanceof IllegalArgumentException);
    assertEquals("Resource " + resourcePath + " is not a file", cause.getMessage());
  }
}
